import{_ as a,o,c as r,a2 as e}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"珍宝馆（宁寿宫区）","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/zhenbao-guan.md","filePath":"landmarks/forbidden-city/zhenbao-guan.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/zhenbao-guan.md"};function l(s,t,i,d,g,h){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="珍宝馆-宁寿宫区" tabindex="-1">珍宝馆（宁寿宫区） <a class="header-anchor" href="#珍宝馆-宁寿宫区" aria-label="Permalink to &quot;珍宝馆（宁寿宫区）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1626502069951-52c5714bfc0f?w=1200&amp;q=80" alt="珍宝馆"></p><blockquote><p>金瓯永固，玉山如岳。这里收藏的不是器物，而是倾一国之力凝固而成的时间与技艺。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>珍宝馆位于故宫东北部的<strong>宁寿宫区域</strong>，是故宫博物院常设的宫廷珍宝专题展馆。宁寿宫区本是乾隆帝为自己退位后颐养天年而预建的&quot;太上皇宫&quot;，占地广阔、规制森严，如今辟为珍宝馆与戏曲文物馆的所在。</p><p>馆藏以清代宫廷珍藏为主体，涵盖<strong>金器、银器、玉器、宝石、珍珠、翡翠、珊瑚、珐琅、漆器</strong>等门类，逾千件展品件件是&quot;不计工本&quot;的皇家制作。这里的每一件器物都不是民间工艺的精品可比——它们使用的是帝国最好的材料、最顶尖的工匠、最漫长的工时，唯一的约束是&quot;天子满意&quot;。</p><p><strong>需另购票10元</strong>（凭故宫大门票在宁寿宫区入口购买）。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>位置</strong></td><td style="text-align:left;">故宫东北部宁寿宫区域（皇极殿、养性殿、乐寿堂等）</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">大门票之外另购10元</td></tr><tr><td style="text-align:left;"><strong>展区</strong></td><td style="text-align:left;">皇极殿东庑、养性殿、乐寿堂、颐和轩等</td></tr><tr><td style="text-align:left;"><strong>藏品门类</strong></td><td style="text-align:left;">金银器、玉器、宝石、珍珠、翡翠、珊瑚、珐琅等</td></tr><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">同故宫开放时间，周一闭馆</td></tr></tbody></table><p>珍宝馆的展厅本身即是文物：宁寿宫区是乾隆三十七年至四十一年（1772-1776年）兴建的太上皇宫，仿紫禁城中轴线规制而建，皇极殿的规制几近乾清宫，养性殿、乐寿堂、颐和轩依次排开，庭院深邃、装修精美。游客在观赏珍宝的同时，也在一座保存完好的乾隆时代宫殿群中穿行。</p><p>展柜中的珍宝按材质与功能分区陈列：金银器展区有祭祀礼器与御用器皿；玉器展区从和田白玉到翡翠山子一应俱全；宝石展区陈列各色红宝石、蓝宝石、猫眼石等朝珠与佩饰；珊瑚、珍珠、翡翠等有机宝石另设专室。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="金瓯永固杯-乾隆的元旦执念" tabindex="-1">金瓯永固杯：乾隆的元旦执念 <a class="header-anchor" href="#金瓯永固杯-乾隆的元旦执念" aria-label="Permalink to &quot;金瓯永固杯：乾隆的元旦执念&quot;">​</a></h3><p><strong>金瓯永固杯</strong>是珍宝馆的镇馆之宝之一，为乾隆帝于乾隆六十二年（1797年，即禅位前一年）下旨制作。&quot;金瓯&quot;喻国家疆土完整，&quot;永固&quot;祈江山万世不移。此杯以黄金铸成，通体镶嵌珍珠、红宝石、蓝宝石，杯身錾刻宝相花，双耳为夔龙，三足为象首——象驮宝瓶，取&quot;太平有象&quot;之意。每年元旦子时，皇帝在养心殿举行&quot;明窗开笔&quot;仪式，将此杯置于御案，注入屠苏酒，写下新年第一笔吉语。金瓯永固杯共制数只，故宫所藏为最精美的一只。它不是一件酒杯，而是一整套帝国新年仪式的核心道具。</p><h3 id="大禹治水图玉山-十年磨一山" tabindex="-1">大禹治水图玉山：十年磨一山 <a class="header-anchor" href="#大禹治水图玉山-十年磨一山" aria-label="Permalink to &quot;大禹治水图玉山：十年磨一山&quot;">​</a></h3><p><strong>大禹治水图玉山</strong>是故宫最大的玉雕，也是中国古代玉雕工程的极限之作。原料是一块重逾五吨的新疆和田青玉（成品高约224厘米），乾隆帝命宫廷画师依宋代《大禹治水图》画稿设计图样，玉料从新疆运至北京耗时三年，再发往扬州由顶尖玉匠雕琢——扬州玉工以&quot;琢玉&quot;闻名天下，此山在扬州雕琢近<strong>十年</strong>方才完工，乾隆五十三年（1788年）运回紫禁城安放于乐寿堂。整座玉山雕刻大禹率众劈山导水、疏浚九河的宏大场面，层峦叠嶂、人物如蚁，雕工精细至极。从开采到落成，前后历时十余年，耗费白银不计其数——它是乾隆盛世&quot;不惜代价追求极致&quot;的物质化石。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>金瓯永固杯</strong>：乾隆御用元旦开笔礼器，黄金嵌宝，是清代宫廷金器的巅峰之作。</li><li><strong>大禹治水图玉山</strong>：高逾两米、耗时十年雕琢的和田青玉巨制，中国古代玉雕的体量之最。</li><li><strong>皇后凤冠</strong>：点翠嵌珠宝凤冠，凤鸟展翅、珠翠交辉，是清代后妃冠饰的极品（注：最著名的翠玉白菜等部分清宫珍宝现藏台北故宫）。</li><li><strong>珊瑚与翡翠陈设</strong>：数尺高的整枝红珊瑚盆景、通体翠绿的翡翠摆件，展示有机宝石的极致运用。</li><li><strong>宁寿宫建筑本身</strong>：皇极殿、乐寿堂的乾隆时代原构装修，与珍宝互为表里。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>预留充足时间</strong>：珍宝馆藏品密集、展线较长，走马观花至少需要40分钟，认真观赏需1-1.5小时。</li><li><strong>先建筑后器物</strong>：进入宁寿宫区后先留意皇极殿、乐寿堂的建筑格局与装修，再看展柜中的珍宝——宫殿是&quot;器&quot;的背景，二者合观才是完整的宫廷艺术。</li><li><strong>避开旅游团</strong>：珍宝馆是旅行团必到之处，上午10点后人流激增，尽量赶早或午后参观。</li><li><strong>注意展柜反光</strong>：馆内玻璃展柜反光较重，穿深色衣物、贴近玻璃拍摄可减少反光。</li><li><strong>与钟表馆联游</strong>：珍宝馆（宁寿宫区）与钟表馆（奉先殿）同在故宫东部，建议一并游览，两馆相距不远。</li></ul><hr><p><strong>📍 位置</strong>：故宫东北部宁寿宫区域（皇极殿、乐寿堂一带） <strong>⏱️ 建议游览</strong>：1-1.5小时 <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/jiulong-bi.html">九龙壁</a>（皇极门外，入宁寿宫区必经） <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/zhongbiao-guan.html">钟表馆（奉先殿）</a><strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',22)])])}const b=a(n,[["render",l]]);export{c as __pageData,b as default};
